import logging
import json
import datetime

class JsonFormatter(logging.Formatter):
    _standard_attributes = {
        'name', 'levelname', 'levelno', 'pathname', 'filename', 'module', 'lineno',
        'funcName', 'created', 'asctime', 'msecs', 'relativeCreated', 'thread',
        'threadName', 'process', 'processName', 'message', 'args', 'exc_info',
        'exc_text', 'stack_info', 'msg', 'stack'
    }

    def __init__(self, fmt=None, datefmt="%Y-%m-%dT%H:%M:%S.%f", style='%', default=None):
        super().__init__(fmt=fmt, datefmt=datefmt, style=style)
        self.default = default or self._default_json_serializer

    def _default_json_serializer(self, obj):
        if isinstance(obj, (datetime.datetime, datetime.date, datetime.time)):
            return obj.isoformat()
        elif isinstance(obj, (set, tuple)):
            return list(obj)
        elif isinstance(obj, Exception):
            return str(obj)
        raise TypeError(f"Object of type {obj.__class__.__name__} is not JSON serializable")

    def format(self, record):
        log_entry = {
            "timestamp": self.formatTime(record, self.datefmt),
            "level": record.levelname,
            "logger": record.name,
            "message": record.getMessage(),
            "module": record.module,
            "funcName": record.funcName,
            "lineno": record.lineno,
            "process": record.process,
            "processName": record.processName,
            "thread": record.thread,
            "threadName": record.threadName,
            "pathname": record.pathname,
            "filename": record.filename,
        }

        if record.exc_info:
            log_entry["exc_info"] = self.formatException(record.exc_info)

        if record.stack_info:
            log_entry["stack_info"] = self.formatStack(record.stack_info)

        for key, value in record.__dict__.items():
            if key not in self._standard_attributes and not key.startswith('_'):
                log_entry[key] = value

        return json.dumps(log_entry, default=self.default, ensure_ascii=False)
